template<typename T>
void verify(const T* ref_out, const T* out, int64_t n)
{
  int error = memcmp(ref_out, out, n * sizeof(T));
  if (error) {
    for (int64_t i = 0; i < n; i++) {
      if (ref_out[i] != out[i]) {
        printf("@%zu: %lf != %lf\n", i, (double)ref_out[i], (double)out[i]);
        break;
      }
    }
  }
  printf("%s\n", error ? "FAIL" : "PASS");
}

#define LOG_MEM_BANKS 5
#define OFFSET(n) ((n) >> LOG_MEM_BANKS)

template<typename T, int N>
__global__ void scan_kernel_with_conflicts(T* in, T* out, int64_t num_blocks) {
  int64_t bid = blockIdx.x;
  if (bid >= num_blocks) return;

  T temp[N];
  int thid = threadIdx.x;

  T* t_in = in + bid * N;
  T* t_out = out + bid * N;

  int offset = 1;

  if (2*thid < N) temp[2*thid] = t_in[2*thid];
  if (2*thid+1 < N) temp[2*thid+1] = t_in[2*thid+1];

  for (int d = N >> 1; d > 0; d >>= 1) {
    __syncthreads();
    if (thid < d) {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      if (bi < N) temp[bi] += temp[ai];
    }
    offset *= 2;
  }

  if (thid == 0) temp[N-1] = 0; 

  for (int d = 1; d < N; d *= 2) {
    offset >>= 1;
    __syncthreads();
    if (thid < d) {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      if (ai < N && bi < N) {
        T t = temp[ai];
        temp[ai] = temp[bi];
        temp[bi] += t;
      }
    }
  }
  __syncthreads();

  if (2*thid < N) t_out[2*thid] = temp[2*thid];
  if (2*thid+1 < N) t_out[2*thid+1] = temp[2*thid+1];
}

template<typename T, int N>
__global__ void scan_kernel_no_conflicts(T* in, T* out, int64_t num_blocks) {
  int64_t bid = blockIdx.x;
  if (bid >= num_blocks) return;

  T temp[2*N]; // Sized to handle offset mapping safely
  int thid = threadIdx.x;

  T* t_in = in + bid * N;
  T* t_out = out + bid * N;

  int a = thid;
  int b = a + (N/2);
  int oa = OFFSET(a);
  int ob = OFFSET(b);

  if (a < N) temp[a + oa] = t_in[a];
  if (b < N) temp[b + ob] = t_in[b];

  int offset = 1;
  for (int d = N >> 1; d > 0; d >>= 1) {
    __syncthreads();
    if (thid < d) {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      ai += OFFSET(ai);
      bi += OFFSET(bi);
      if (bi < 2*N) temp[bi] += temp[ai];
    }
    offset *= 2;
  }

  if (thid == 0) {
    int idx = N-1 + OFFSET(N-1);
    if (idx < 2*N) temp[idx] = 0;
  }

  for (int d = 1; d < N; d *= 2) {
    offset >>= 1;
    __syncthreads();
    if (thid < d) {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      ai += OFFSET(ai);
      bi += OFFSET(bi);
      if (ai < 2*N && bi < 2*N) {
        T t = temp[ai];
        temp[ai] = temp[bi];
        temp[bi] += t;
      }
    }
  }
  __syncthreads();

  if (a < N) t_out[a] = temp[a + oa];
  if (b < N) t_out[b] = temp[b + ob];
}

template<typename T, int N>
void runTest (const int64_t n, const int repeat, bool timing = false)
{
  int64_t num_blocks = (n + N - 1) / N;
  int64_t nelems = num_blocks * N;
  int64_t bytes = nelems * sizeof(T);

  T *in_host = (T*) malloc (bytes);
  T *out_host = (T*) malloc (bytes);
  T *ref_out_host = (T*) malloc (bytes);

  srand(123);
  for (int64_t k = 0; k < nelems; k++) in_host[k] = rand() % 5 + 1;

  // Compute reference on CPU
  T *t_in = in_host;
  T *t_out = ref_out_host;
  for (int64_t k = 0; k < num_blocks; k++) {
    t_out[0] = 0;
    for (int i = 1; i < N; i++)
      t_out[i] = t_out[i-1] + t_in[i-1];
    t_out += N;
    t_in += N;
  }

  T *in_dev, *out_dev;
  cudaMalloc(&in_dev, bytes);
  cudaMalloc(&out_dev, bytes);
  cudaMemcpy(in_dev, in_host, bytes, cudaMemcpyHostToDevice);

  int threads_per_block = N/2;
  dim3 block_dim(threads_per_block);
  dim3 num_teams_dim(num_blocks);

  // First pass: With bank conflicts
  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    scan_kernel_with_conflicts<T, N><<num_teams_dim, block_dim>>>(in_dev, out_dev, num_blocks);
  }

  auto end = std::chrono::steady_clock::now();
  auto time_ns = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();

  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/  bank conflicts): %f (us)\n",
           sizeof(T), (time_ns * 1e-3f) / repeat);
  }

  cudaMemcpy(out_host, out_dev, bytes, cudaMemcpyDeviceToHost);
  if (!timing) verify(ref_out_host, out_host, nelems);

  // Second pass: Without bank conflicts
  start = std::chrono::steady_clock::now();
  for (int i = 0; i < repeat; i++) {
    scan_kernel_no_conflicts<T, N><<num_teams_dim, block_dim>>>(in_dev, out_dev, num_blocks);
  }

  end = std::chrono::steady_clock::now();
  auto bcao_time_ns = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();

  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/o bank conflicts): %f (us). ",
           sizeof(T), (bcao_time_ns * 1e-3f) / repeat);
    printf("Reduce the time by %.1f%%\n", (time_ns - bcao_time_ns) * 1.0 / time_ns * 100);
  }

  cudaMemcpy(out_host, out_dev, bytes, cudaMemcpyDeviceToHost);
  if (!timing) verify(ref_out_host, out_host, nelems);

  cudaFree(in_dev);
  cudaFree(out_dev);
  free(in_host);
  free(out_host);
  free(ref_out_host);
}

template<int N>
void run (const int n, const int repeat) {
  for (int i = 0; i < 2; i++) {
    bool report_timing = i > 0;
    printf("\nThe number of elements to scan in a thread block: %d\n", N);
    runTest< char, N>(n, repeat, report_timing);
    runTest<short, N>(n, repeat, report_timing);
    runTest<  int, N>(n, repeat, report_timing);
    runTest< long, N>(n, repeat, report_timing);
